# Use Python with pyelftools + the DWARF info to symbolicate
python3 << 'PYEOF'
from elftools.elf.elffile import ELFFile
from elftools.dwarf.descriptions import describe_form_class

def symbolicate_address(dwarfinfo, address):
    """Look up function name and source location for an address."""
    func_name = None
    file_line = None

    # Search CUs for line info
    for CU in dwarfinfo.iter_CUs():
        try:
            lineprog = dwarfinfo.line_program_for_CU(CU)
        except Exception:
            continue
        if lineprog is None:
            continue

        prev_state = None
        for entry in lineprog.get_entries():
            if entry.state is None:
                continue
            if prev_state and not prev_state.end_sequence:
                if prev_state.address <= address < entry.state.address:
                    file_entry = lineprog['file_entry'][prev_state.file - 1]
                    dir_index = file_entry.dir_index
                    if dir_index > 0:
                        dir_name = lineprog['include_directory'][dir_index - 1]
                        if isinstance(dir_name, bytes):
                            dir_name = dir_name.decode('utf-8', errors='replace')
                    else:
                        dir_name = '.'
                    fname = file_entry.name
                    if isinstance(fname, bytes):
                        fname = fname.decode('utf-8', errors='replace')
                    file_line = f"{dir_name}/{fname}:{prev_state.line}"
                    break
            prev_state = entry.state
        if file_line:
            break

    # Search for function name in .symtab or DWARF
    # Try DWARF DIEs first
    for CU in dwarfinfo.iter_CUs():
        for DIE in CU.iter_DIEs():
            if DIE.tag == 'DW_TAG_subprogram':
                try:
                    lo = DIE.attributes.get('DW_AT_low_pc')
                    hi = DIE.attributes.get('DW_AT_high_pc')
                    if lo is None:
                        continue
                    lo_val = lo.value
                    if hi is not None:
                        hi_class = describe_form_class(hi.form)
                        if hi_class == 'constant':
                            hi_val = lo_val + hi.value
                        else:
                            hi_val = hi.value
                    else:
                        hi_val = lo_val + 1

                    if lo_val <= address < hi_val:
                        name = DIE.attributes.get('DW_AT_name')
                        if name:
                            n = name.value
                            if isinstance(n, bytes):
                                n = n.decode('utf-8', errors='replace')
                            func_name = n
                            # Check for linkage name too
                            ln = DIE.attributes.get('DW_AT_linkage_name')
                            if ln:
                                lnv = ln.value
                                if isinstance(lnv, bytes):
                                    lnv = lnv.decode('utf-8', errors='replace')
                                func_name = lnv
                            break
                except Exception:
                    continue
        if func_name:
            break

    return func_name, file_line

# Also check symtab
def get_symbol_name(elffile, address):
    symtab = elffile.get_section_by_name('.symtab')
    if symtab is None:
        symtab = elffile.get_section_by_name('.dynsym')
    if symtab is None:
        return None
    best = None
    best_dist = float('inf')
    for sym in symtab.iter_symbols():
        if sym['st_info']['type'] in ('STT_FUNC', 'STT_NOTYPE'):
            sv = sym['st_value']
            sz = sym['st_size']
            if sv <= address < sv + max(sz, 1):
                dist = address - sv
                if dist < best_dist:
                    best = sym.name
                    best_dist = dist
    return best

# Addresses from tombstone (PC offsets into libmonosgen-2.0.so)
addresses = {
    '#01': 0x222098,
    '#02': 0x2241ac,
    '#03': 0x1abc80,
    '#04': 0x1abd14,
    '#05': 0x16dfa4,
    '#06': 0x16db6c,
    '#07': 0x16de04,
}

debug_path = '/tmp/symbols/libmonosgen-2.0.so.debug'

with open(debug_path, 'rb') as f:
    elffile = ELFFile(f)
    dwarfinfo = elffile.get_dwarf_info()

    print("Symbolicated backtrace for libmonosgen-2.0.so:")
    print("=" * 80)
    print(f"  #00 pc 000000000006ae1c  libc.so (abort+164)")

    for frame, addr in addresses.items():
        sym = get_symbol_name(elffile, addr)
        func_name, file_line = symbolicate_address(dwarfinfo, addr)

        display_name = func_name or sym or "??"
        loc = file_line or "??:?"
        print(f"  {frame} pc {addr:016x}  libmonosgen-2.0.so ({display_name}) at {loc}")

    print(f"  #08 pc 000000000000307c  <anonymous/JIT code>")
    print("=" * 80)

